-- ============================================-- 义齿工厂招聘系统 - 后台字段设置系统数据库表创建脚本-- 请在 Supabase SQL Editor 中执行此脚本-- ============================================\n\n-- 1. 创建字段基础配置表CREATE TABLE IF NOT EXISTS field_configs (  id SERIAL PRIMARY KEY,  field_name VARCHAR(255) NOT NULL,  field_label VARCHAR(255) NOT NULL,  field_type VARCHAR(50) NOT NULL,  is_required BOOLEAN NOT NULL DEFAULT false,  validation_rules JSONB,  default_value TEXT,  placeholder VARCHAR(255),  created_at TIMESTAMP NOT NULL DEFAULT NOW(),  updated_at TIMESTAMP NOT NULL DEFAULT NOW());\n\n-- 2. 创建岗位模板表CREATE TABLE IF NOT EXISTS position_templates (  id SERIAL PRIMARY KEY,  template_name VARCHAR(255) NOT NULL,  description TEXT,  is_active BOOLEAN NOT NULL DEFAULT true,  created_at TIMESTAMP NOT NULL DEFAULT NOW(),  updated_at TIMESTAMP NOT NULL DEFAULT NOW());\n\n-- 3. 创建模板与字段关联表CREATE TABLE IF NOT EXISTS template_field_mappings (  id SERIAL PRIMARY KEY,  template_id INTEGER NOT NULL REFERENCES position_templates(id) ON DELETE CASCADE,  field_id INTEGER NOT NULL REFERENCES field_configs(id) ON DELETE CASCADE,  sort_order INTEGER NOT NULL DEFAULT 0,  is_enabled BOOLEAN NOT NULL DEFAULT true,  created_at TIMESTAMP NOT NULL DEFAULT NOW());\n\n-- 4. 创建字段选项配置表CREATE TABLE IF NOT EXISTS field_option_configs (  id SERIAL PRIMARY KEY,  field_id INTEGER NOT NULL REFERENCES field_configs(id) ON DELETE CASCADE,  option_value VARCHAR(255) NOT NULL,  option_label VARCHAR(255) NOT NULL,  sort_order INTEGER NOT NULL DEFAULT 0,  has_attachments BOOLEAN NOT NULL DEFAULT false,  created_at TIMESTAMP NOT NULL DEFAULT NOW());\n\n-- 5. 创建选项附加信息配置表CREATE TABLE IF NOT EXISTS attachment_configs (  id SERIAL PRIMARY KEY,  option_config_id INTEGER NOT NULL REFERENCES field_option_configs(id) ON DELETE CASCADE,  field_name VARCHAR(255) NOT NULL,  field_label VARCHAR(255) NOT NULL,  field_type VARCHAR(50) NOT NULL,  is_required BOOLEAN NOT NULL DEFAULT false,  sort_order INTEGER NOT NULL DEFAULT 0,  created_at TIMESTAMP NOT NULL DEFAULT NOW());\n\n-- 6. 创建配置版本历史表CREATE TABLE IF NOT EXISTS config_versions (  id SERIAL PRIMARY KEY,  entity_type VARCHAR(50) NOT NULL,  entity_id INTEGER NOT NULL,  operation VARCHAR(20) NOT NULL,  old_data JSONB,  new_data JSONB,  user_id VARCHAR(255),  created_at TIMESTAMP NOT NULL DEFAULT NOW());\n\n-- 7. 创建索引CREATE INDEX IF NOT EXISTS idx_field_configs_field_name ON field_configs(field_name);CREATE INDEX IF NOT EXISTS idx_position_templates_is_active ON position_templates(is_active);CREATE INDEX IF NOT EXISTS idx_template_field_mappings_template_id ON template_field_mappings(template_id);CREATE INDEX IF NOT EXISTS idx_template_field_mappings_field_id ON template_field_mappings(field_id);CREATE INDEX IF NOT EXISTS idx_field_option_configs_field_id ON field_option_configs(field_id);CREATE INDEX IF NOT EXISTS idx_attachment_configs_option_config_id ON attachment_configs(option_config_id);CREATE INDEX IF NOT EXISTS idx_config_versions_entity_type ON config_versions(entity_type);CREATE INDEX IF NOT EXISTS idx_config_versions_entity_id ON config_versions(entity_id);\n\n-- 8. 设置行级安全策略ALTER TABLE field_configs ENABLE ROW LEVEL SECURITY;ALTER TABLE position_templates ENABLE ROW LEVEL SECURITY;ALTER TABLE template_field_mappings ENABLE ROW LEVEL SECURITY;ALTER TABLE field_option_configs ENABLE ROW LEVEL SECURITY;ALTER TABLE attachment_configs ENABLE ROW LEVEL SECURITY;ALTER TABLE config_versions ENABLE ROW LEVEL SECURITY;\n\n-- 9. 允许匿名访问（临时，生产环境应设置权限控制）CREATE POLICY "Allow anonymous select on field_configs" ON field_configs  FOR SELECT TO anon USING (true);\n\nCREATE POLICY "Allow anonymous insert on field_configs" ON field_configs  FOR INSERT TO anon WITH CHECK (true);\n\nCREATE POLICY "Allow anonymous update on field_configs" ON field_configs  FOR UPDATE TO anon USING (true) WITH CHECK (true);\n\nCREATE POLICY "Allow anonymous delete on field_configs" ON field_configs  FOR DELETE TO anon USING (true);\n\nCREATE POLICY "Allow anonymous select on position_templates" ON position_templates  FOR SELECT TO anon USING (true);\n\nCREATE POLICY "Allow anonymous insert on position_templates" ON position_templates  FOR INSERT TO anon WITH CHECK (true);\n\nCREATE POLICY "Allow anonymous update on position_templates" ON position_templates  FOR UPDATE TO anon USING (true) WITH CHECK (true);\n\nCREATE POLICY "Allow anonymous delete on position_templates" ON position_templates  FOR DELETE TO anon USING (true);\n\nCREATE POLICY "Allow anonymous select on template_field_mappings" ON template_field_mappings  FOR SELECT TO anon USING (true);\n\nCREATE POLICY "Allow anonymous insert on template_field_mappings" ON template_field_mappings  FOR INSERT TO anon WITH CHECK (true);\n\nCREATE POLICY "Allow anonymous update on template_field_mappings" ON template_field_mappings  FOR UPDATE TO anon USING (true) WITH CHECK (true);\n\nCREATE POLICY "Allow anonymous delete on template_field_mappings" ON template_field_mappings  FOR DELETE TO anon USING (true);\n\nCREATE POLICY "Allow anonymous select on field_option_configs" ON field_option_configs  FOR SELECT TO anon USING (true);\n\nCREATE POLICY "Allow anonymous insert on field_option_configs" ON field_option_configs  FOR INSERT TO anon WITH CHECK (true);\n\nCREATE POLICY "Allow anonymous update on field_option_configs" ON field_option_configs  FOR UPDATE TO anon USING (true) WITH CHECK (true);\n\nCREATE POLICY "Allow anonymous delete on field_option_configs" ON field_option_configs  FOR DELETE TO anon USING (true);\n\nCREATE POLICY "Allow anonymous select on attachment_configs" ON attachment_configs  FOR SELECT TO anon USING (true);\n\nCREATE POLICY "Allow anonymous insert on attachment_configs" ON attachment_configs  FOR INSERT TO anon WITH CHECK (true);\n\nCREATE POLICY "Allow anonymous update on attachment_configs" ON attachment_configs  FOR UPDATE TO anon USING (true) WITH CHECK (true);\n\nCREATE POLICY "Allow anonymous delete on attachment_configs" ON attachment_configs  FOR DELETE TO anon USING (true);\n\nCREATE POLICY "Allow anonymous select on config_versions" ON config_versions  FOR SELECT TO anon USING (true);\n\nCREATE POLICY "Allow anonymous insert on config_versions" ON config_versions  FOR INSERT TO anon WITH CHECK (true);\n\n-- 10. 插入默认字段配置数据INSERT INTO field_configs (field_name, field_label, field_type, is_required, validation_rules, placeholder) VALUES('name', '姓名', 'text', true, null, '请输入姓名'),('phone', '联系电话', 'text', true, '{"pattern": "^1[3-9]\\d{9}$", "message": "请输入正确的手机号码"}', '请输入手机号码'),('age', '年龄', 'number', true, '{"min": 18, "max": 65, "message": "年龄必须在18-65之间"}', '请输入年龄'),('education', '学历', 'select', true, null, '请选择学历'),('work_experience', '工作经验', 'select', false, null, '请选择工作经验'),('source', '来源渠道', 'select', false, null, '请选择来源渠道'),('willing_shift', '是否愿意倒班', 'radio', false, null, null),('expected_salary', '期望薪资', 'number', false, '{"min": 0, "message": "请输入有效的薪资"}', '请输入期望薪资'),('self_introduction', '自我介绍', 'textarea', false, null, '请简要介绍自己'),('apply_position', '应聘岗位', 'select', true, null, '请选择应聘岗位');\n\n-- 11. 插入学历选项INSERT INTO field_option_configs (field_id, option_value, option_label, sort_order) SELECT id, 'high_school', '高中', 1 FROM field_configs WHERE field_name = 'education';INSERT INTO field_option_configs (field_id, option_value, option_label, sort_order) SELECT id, 'vocational', '中专/职高', 2 FROM field_configs WHERE field_name = 'education';INSERT INTO field_option_configs (field_id, option_value, option_label, sort_order) SELECT id, 'college', '大专', 3 FROM field_configs WHERE field_name = 'education';INSERT INTO field_option_configs (field_id, option_value, option_label, sort_order) SELECT id, 'bachelor', '本科', 4 FROM field_configs WHERE field_name = 'education';INSERT INTO field_option_configs (field_id, option_value, option_label, sort_order) SELECT id, 'master', '硕士及以上', 5 FROM field_configs WHERE field_name = 'education';\n\n-- 12. 插入工作经验选项INSERT INTO field_option_configs (field_id, option_value, option_label, sort_order) SELECT id, 'no_experience', '无经验', 1 FROM field_configs WHERE field_name = 'work_experience';INSERT INTO field_option_configs (field_id, option_value, option_label, sort_order) SELECT id, '1_year', '1年以下', 2 FROM field_configs WHERE field_name = 'work_experience';INSERT INTO field_option_configs (field_id, option_value, option_label, sort_order) SELECT id, '1_3_years', '1-3年', 3 FROM field_configs WHERE field_name = 'work_experience';INSERT INTO field_option_configs (field_id, option_value, option_label, sort_order) SELECT id, '3_5_years', '3-5年', 4 FROM field_configs WHERE field_name = 'work_experience';INSERT INTO field_option_configs (field_id, option_value, option_label, sort_order) SELECT id, '5_years', '5年以上', 5 FROM field_configs WHERE field_name = 'work_experience';\n\n-- 13. 插入来源渠道选项INSERT INTO field_option_configs (field_id, option_value, option_label, sort_order, has_attachments) SELECT id, 'online', '网络招聘', 1, false FROM field_configs WHERE field_name = 'source';INSERT INTO field_option_configs (field_id, option_value, option_label, sort_order, has_attachments) SELECT id, 'internal', '内部介绍', 2, true FROM field_configs WHERE field_name = 'source';INSERT INTO field_option_configs (field_id, option_value, option_label, sort_order, has_attachments) SELECT id, 'other', '其他', 3, true FROM field_configs WHERE field_name = 'source';\n\n-- 14. 插入是否愿意倒班选项INSERT INTO field_option_configs (field_id, option_value, option_label, sort_order) SELECT id, 'yes', '是', 1 FROM field_configs WHERE field_name = 'willing_shift';INSERT INTO field_option_configs (field_id, option_value, option_label, sort_order) SELECT id, 'no', '否', 2 FROM field_configs WHERE field_name = 'willing_shift';\n\n-- 15. 插入来源渠道附加信息配置WITH internal_option AS (  SELECT id FROM field_option_configs WHERE option_value = 'internal')INSERT INTO attachment_configs (option_config_id, field_name, field_label, field_type, is_required, sort_order) SELECT id, 'recommender_name', '推荐人姓名', 'text', true, 1 FROM internal_option;\n\nWITH other_option AS (  SELECT id FROM field_option_configs WHERE option_value = 'other')INSERT INTO attachment_configs (option_config_id, field_name, field_label, field_type, is_required, sort_order) SELECT id, 'other_source', '具体来源', 'text', true, 1 FROM other_option;\n\n-- 16. 插入默认岗位模板INSERT INTO position_templates (template_name, description, is_active) VALUES('义齿设计师', '义齿设计师岗位申请表单配置', true),('CAD/CAM技术员', 'CAD/CAM技术员岗位申请表单配置', true),('模型制作员', '模型制作员岗位申请表单配置', true),('烤瓷技术员', '烤瓷技术员岗位申请表单配置', true),('质检员', '质检员岗位申请表单配置', true),('生产主管', '生产主管岗位申请表单配置', true),('其他岗位', '其他岗位申请表单配置', true);\n\n-- 17. 为每个模板添加默认字段\n-- 义齿设计师模板WITH designer_template AS (  SELECT id FROM position_templates WHERE template_name = '义齿设计师'),field_ids AS (  SELECT id, field_name FROM field_configs)INSERT INTO template_field_mappings (template_id, field_id, sort_order, is_enabled) SELECT  dt.id, fi.id,  CASE    WHEN fi.field_name = 'name' THEN 1    WHEN fi.field_name = 'phone' THEN 2    WHEN fi.field_name = 'age' THEN 3    WHEN fi.field_name = 'education' THEN 4    WHEN fi.field_name = 'work_experience' THEN 5    WHEN fi.field_name = 'source' THEN 6    WHEN fi.field_name = 'willing_shift' THEN 7    WHEN fi.field_name = 'expected_salary' THEN 8    WHEN fi.field_name = 'self_introduction' THEN 9    WHEN fi.field_name = 'apply_position' THEN 10    ELSE 99  END,  trueFROM designer_template dt, field_ids fi;\n\n-- CAD/CAM技术员模板WITH cad_template AS (  SELECT id FROM position_templates WHERE template_name = 'CAD/CAM技术员'),field_ids AS (  SELECT id, field_name FROM field_configs)INSERT INTO template_field_mappings (template_id, field_id, sort_order, is_enabled) SELECT  ct.id, fi.id,  CASE    WHEN fi.field_name = 'name' THEN 1    WHEN fi.field_name = 'phone' THEN 2    WHEN fi.field_name = 'age' THEN 3    WHEN fi.field_name = 'education' THEN 4    WHEN fi.field_name = 'work_experience' THEN 5    WHEN fi.field_name = 'source' THEN 6    WHEN fi.field_name = 'willing_shift' THEN 7    WHEN fi.field_name = 'expected_salary' THEN 8    WHEN fi.field_name = 'self_introduction' THEN 9    WHEN fi.field_name = 'apply_position' THEN 10    ELSE 99  END,  trueFROM cad_template ct, field_ids fi;\n\n-- 其他模板类似添加字段映射...\n\n-- 完成SELECT '后台字段设置系统数据库表创建成功！' as message;